package com.maum.backend.call.exception

import com.maum.backend.call.domain.CallMatchStatus

class AlreadyInMatchException(
    val userId: String,
    val currentStatus: CallMatchStatus
) : RuntimeException("User $userId is already in match status: $currentStatus")

class MatchNotFoundException(
    val matchId: String
) : RuntimeException("Match not found: $matchId")

class MatchExpiredException(
    val matchId: String
) : RuntimeException("Match expired: $matchId")

class InvalidMatchStateException(
    val matchId: String,
    val currentStatus: CallMatchStatus
) : RuntimeException("Invalid match state for operation: $currentStatus (matchId=$matchId)")

class UnauthorizedMatchAccessException(
    val userId: String,
    val matchId: String
) : RuntimeException("User $userId is not authorized to access match $matchId")

class CannotCancelActiveCallException(
    val matchId: String
) : RuntimeException("Cannot cancel a call that is IN_CALL: $matchId")
